import { useNavigate } from "react-router-dom";
import Navbar from "../components/Navbar";

export default function Home() {

  const nav = useNavigate();

  return (

    <div style={styles.page}>

      <Navbar />

      <div style={styles.hero}>

        <h1 style={styles.title}>
          Find Daily Workers Easily
        </h1>

        <p style={styles.subtitle}>
          Hire trusted workers near you for
          everyday jobs and services.
        </p>

        <div style={styles.buttons}>

          <button
            style={styles.loginBtn}
            onClick={() => nav("/login")}
          >
            Login
          </button>

          <button
            style={styles.registerBtn}
            onClick={() => nav("/register")}
          >
            Register
          </button>

        </div>

      </div>

    </div>
  );
}

const styles = {

  page: {
    minHeight: "100vh",
    background: "#f7f9fc",
    fontFamily: "Arial, sans-serif"
  },

  hero: {
    height: "80vh",
    display: "flex",
    flexDirection: "column",
    justifyContent: "center",
    alignItems: "center",
    textAlign: "center",
    padding: "20px"
  },

  title: {
    fontSize: "40px",
    color: "#111827",
    marginBottom: "15px",
    fontWeight: "600"
  },

  subtitle: {
    fontSize: "16px",
    color: "#6b7280",
    maxWidth: "500px",
    lineHeight: "28px",
    marginBottom: "30px"
  },

  buttons: {
    display: "flex",
    gap: "15px"
  },

  loginBtn: {
    background: "#2563eb",
    color: "white",
    border: "none",
    padding: "13px 28px",
    borderRadius: "8px",
    cursor: "pointer",
    fontSize: "14px"
  },

  registerBtn: {
    background: "white",
    border: "1px solid #d1d5db",
    padding: "13px 28px",
    borderRadius: "8px",
    cursor: "pointer",
    fontSize: "14px"
  }

};
